def ec_add(P: tuple, Q: tuple, a: int, p: int) -> tuple:
    if P is None:
        return Q
    if Q is None:
        return P

    x1, y1 = P
    x2, y2 = Q

    if x1 == x2 and (y1 + y2) % p == 0:
        return None  # P + (-P) = O

    if x1 == x2 and y1 == y2:
        # Point doubling
        num = (3 * x1 * x1 + a) % p
        den = (2 * y1) % p
    else:
        # Point addition
        num = (y2 - y1) % p
        den = (x2 - x1) % p

    lam = (num * pow(den, p - 2, p)) % p
    x3 = (lam * lam - x1 - x2) % p
    y3 = (lam * (x1 - x3) - y1) % p

    return (x3, y3)

