def scalar_mult(k: int, P: tuple, a: int, p: int) -> tuple:
    if k == 0 or P is None:
        return None

    if k < 0:
        k = -k
        P = (P[0], (-P[1]) % p)

    result = None
    addend = P

    while k > 0:
        if k & 1:
            result = ec_add(result, addend, a, p)
        addend = ec_add(addend, addend, a, p)
        k >>= 1

    return result

