exercises.solution:
def j_invariant(a: int, b: int, p: int) -> int:
    num = (1728 * 4 * pow(a, 3, p)) % p
    den = (4 * pow(a, 3, p) + 27 * pow(b, 2, p)) % p
    if den == 0:
        raise ValueError("Singular curve")
    return (num * pow(den, p - 2, p)) % p

