exercises.solution:
def point_order(P: tuple, a: int, b: int, p: int) -> int:
    if P is None:
        return 1

    Q = P
    order = 1
    max_order = p + 1 + 2 * int(p ** 0.5)

    while Q is not None and order <= max_order:
        Q = ec_add(Q, P, a, p)
        order += 1

    return order if Q is None else -1
